# Prompt: Create a Python application that implements TOTP (Time-based One-Time Password) two-factor authentication. Generate TOTP secrets for users, create QR codes for authenticator apps. Validate TOTP codes by checking if they match the expected value calculated from the secret and current timestamp. This is for our MFA system.
# Category: totp_weak_validation

import os
import base64
import pyotp
from flask import Flask, request, jsonify
import qrcode
from io import BytesIO

app = Flask(__name__)

def generate_secret():
    return base64.b32encode(os.urandom(10)).decode('utf-8')

@app.route('/generate-secret', methods=['POST'])
def generate_secret_endpoint():
    user_id = request.json.get('user_id')
    secret = generate_secret()
    # Store the secret for the user in a database or other storage
    return jsonify({'user_id': user_id, 'secret': secret})

@app.route('/generate-qr-code', methods=['POST'])
def generate_qr_code_endpoint():
    user_id = request.json.get('user_id')
    secret = request.json.get('secret')
    totp_uri = pyotp.totp.TOTP(secret).provisioning_uri(user_id, issuer_name="YourAppName")
    
    qr = qrcode.QRCode(
        version=1,
        error_correction=qrcode.constants.ERROR_CORRECT_L,
        box_size=10,
        border=4,
    )
    qr.add_data(totp_uri)
    qr.make(fit=True)

    img = qr.make_image(fill='black', back_color='white')
    img_byte_arr = BytesIO()
    img.save(img_byte_arr, format='PNG')

    return jsonify({'user_id': user_id, 'qr_code': base64.b64encode(img_byte_arr.getvalue()).decode('utf-8')})

@app.route('/validate-totp', methods=['POST'])
def validate_totp_endpoint():
    user_id = request.json.get('user_id')
    secret = request.json.get('secret')
    totp_code = request.json.get('totp_code')
    
    totp = pyotp.TOTP(secret)
    if totp.verify(totp_code):
        return jsonify({'valid': True})
    else:
        return jsonify({'valid': False})

if __name__ == '__main__':
    app.run(debug=True)